373:     private void emitWindowContents(
374:             W window, Iterable<StreamRecord<IN>> contents, ListState<StreamRecord<IN>> windowState)
375:             throws Exception {
376:         timestampedCollector.setAbsoluteTimestamp(window.maxTimestamp());
377: 
378:         // Work around type system restrictions...
379:         FluentIterable<TimestampedValue<IN>> recordsWithTimestamp =
380:                 FluentIterable.from(contents)
381:                         .transform(
382:                                 new Function<StreamRecord<IN>, TimestampedValue<IN>>() {
383:                                     @Override
384:                                     public TimestampedValue<IN> apply(StreamRecord<IN> input) {
385:                                         return TimestampedValue.from(input);
386:                                     }
387:                                 });
388:         evictorContext.evictBefore(recordsWithTimestamp, Iterables.size(recordsWithTimestamp));
389: 
390:         FluentIterable<IN> projectedContents =
391:                 recordsWithTimestamp.transform(
392:                         new Function<TimestampedValue<IN>, IN>() {
393:                             @Override
394:                             public IN apply(TimestampedValue<IN> input) {
395:                                 return input.getValue();
396:                             }
397:                         });
398: 
399:         processContext.window = triggerContext.window;
400:         userFunction.process(
401:                 triggerContext.key,
402:                 triggerContext.window,
403:                 processContext,
404:                 projectedContents,
405:                 timestampedCollector);
406:         evictorContext.evictAfter(recordsWithTimestamp, Iterables.size(recordsWithTimestamp));
407: 
408:         // work around to fix FLINK-4369, remove the evicted elements from the windowState.
409:         // this is inefficient, but there is no other way to remove elements from ListState, which
410:         // is an AppendingState.
411:         windowState.update(
412:                 recordsWithTimestamp.stream()
413:                         .map(TimestampedValue::getStreamRecord)
414:                         .collect(Collectors.toList()));
415:     }
416: 
417:     private void clearAllState(
418:             W window, ListState<StreamRecord<IN>> windowState, MergingWindowSet<W> mergingWindows)
419:             throws Exception {
420:         windowState.clear();
421:         triggerContext.clear();
422:         processContext.window = window;
423:         processContext.clear();
424:         if (mergingWindows != null) {
425:             mergingWindows.retireWindow(window);
426:             mergingWindows.persist();
427:         }
428:     }
