/*
 * Test case for late data side output with merging session windows
 *
 * This test demonstrates the bug where late-arriving data elements
 * that should be emitted to a side output are silently dropped when
 * using session windows (merging windows) with allowedLateness=0.
 *
 * Bug: When an element arrives after the watermark and the merged
 * window would be late, the element should be side-outputted as late,
 * but instead it's being dropped silently.
 */

package org.apache.flink.streaming.runtime.operators.windowing;

import org.apache.flink.api.common.serialization.SerializerConfigImpl;
import org.apache.flink.api.common.state.ReducingStateDescriptor;
import org.apache.flink.api.common.typeinfo.BasicTypeInfo;
import org.apache.flink.api.common.typeinfo.TypeInformation;
import org.apache.flink.api.java.tuple.Tuple2;
import org.apache.flink.api.java.tuple.Tuple3;
import org.apache.flink.streaming.api.operators.OneInputStreamOperatorFactory;
import org.apache.flink.streaming.api.watermark.Watermark;
import org.apache.flink.streaming.api.windowing.assigners.EventTimeSessionWindows;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
import org.apache.flink.streaming.runtime.operators.windowing.functions.InternalSingleValueWindowFunction;
import org.apache.flink.streaming.runtime.streamrecord.StreamRecord;
import org.apache.flink.streaming.util.KeyedOneInputStreamOperatorTestHarness;
import org.apache.flink.streaming.util.OneInputStreamOperatorTestHarness;
import org.apache.flink.streaming.util.TestHarnessUtil;
import org.apache.flink.util.OutputTag;
import org.junit.jupiter.api.Test;

import java.time.Duration;
import java.util.concurrent.ConcurrentLinkedQueue;

import static org.assertj.core.api.Assertions.assertThat;

class LateDataMergingWindowsTest {
    private static final TypeInformation<Tuple2<String, Integer>> STRING_INT_TUPLE =
            TypeInformation.of(new org.apache.flink.api.common.typeinfo.TypeHint<Tuple2<String, Integer>>() {});

    private static final OutputTag<Tuple2<String, Integer>> lateOutputTag =
            new OutputTag<Tuple2<String, Integer>>("late-output") {};

    /**
     * Test case: Late element that could extend a session window should be side-outputted
     *
     * Scenario:
     * 1. Element E1 arrives at T=1000, creates session window [1000, 4000]
     * 2. Watermark advances to T=3999
     * 3. Element E2 arrives at T=3800 (within session gap), would extend to [1000, 6800]
     * 4. Watermark advances to T=4001
     * 5. Element E3 arrives at T=3500 (after watermark, could extend [1000, 6300])
     *    - isElementLate(E3) returns true because T=3500 + allowedLateness=0 <= 4001
     *    - But E3 could extend the window, so it should be processed, not side-outputted
     *
     * Expected: E3 should be side-outputted as late since the window is already closed
     */
    @Test
    void testLateDataWithSessionWindowZeroLateness() throws Exception {
        final int gapSize = 3; // 3000 ms gap
        final long allowedLateness = 0; // No allowed lateness

        ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
                new ReducingStateDescriptor<>(
                        "window-contents",
                        new SumReducer(),
                        STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

        WindowOperatorFactory<
                String,
                Tuple2<String, Integer>,
                Tuple2<String, Integer>,
                Tuple3<String, Long, Long>,
                TimeWindow>
        operator =
                new WindowOperatorFactory<>(
                        EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                        new TimeWindow.Serializer(),
                        new TupleKeySelector(),
                        BasicTypeInfo.STRING_TYPE_INFO.createSerializer(new SerializerConfigImpl()),
                        stateDesc,
                        new InternalSingleValueWindowFunction<>(new ReducedSessionWindowFunction()),
                        EventTimeTrigger.create(),
                        allowedLateness,
                        lateOutputTag);

        OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
                testHarness = createTestHarness(operator);

        testHarness.open();

        ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
        ConcurrentLinkedQueue<Object> sideOutputExpected = new ConcurrentLinkedQueue<>();

        // Element 1: Create session window [1000, 4000]
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 1000));

        // Advance watermark to 3999 (before window closes)
        testHarness.processWatermark(new Watermark(3999));
        expected.add(new Watermark(3999));

        // Element 2: Arrive at T=3800, extends window to [1000, 6800]
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 3800));

        // Advance watermark to 4001 (window [1000, 4000] is now closed)
        testHarness.processWatermark(new Watermark(4001));
        expected.add(new Watermark(4001));

        // Element 3: Arrive at T=3500, after watermark, could extend [1000, 6300]
        // This element is late (3500 + 0 <= 4001) but should be side-outputted
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 3500));
        sideOutputExpected.add(new StreamRecord<>(new Tuple2<>("key1", 1), 3500));

        // Continue processing
        testHarness.processWatermark(new Watermark(10000));
        expected.add(new StreamRecord<>(new Tuple3<>("key1-3", 1000L, 6800L), 6799));
        expected.add(new Watermark(10000));

        // Verify main output
        ConcurrentLinkedQueue<Object> actual = testHarness.getOutput();
        TestHarnessUtil.assertOutputEqualsSorted(
                "Output was not correct.", expected, actual, new Tuple2ResultSortComparator());

        // Verify side output - THIS IS THE KEY TEST
        ConcurrentLinkedQueue<StreamRecord<Tuple2<String, Integer>>> sideActual =
                testHarness.getSideOutput(lateOutputTag);

        assertThat(sideActual).isNotNull().as("Side output should not be null");
        assertThat(sideActual).isNotEmpty().as("Late element should be in side output");

        testHarness.close();
    }

    // Helper classes and methods...

    private static class SumReducer implements org.apache.flink.api.common.functions.ReduceFunction<Tuple2<String, Integer>> {
        @Override
        public Tuple2<String, Integer> reduce(Tuple2<String, Integer> value1, Tuple2<String, Integer> value2) throws Exception {
            return new Tuple2<>(value1.f0, value1.f1 + value2.f1);
        }
    }

    private static class ReducedSessionWindowFunction extends org.apache.flink.streaming.api.functions.windowing.WindowFunction<Tuple2<String, Integer>, Tuple3<String, Long, Long>, String, TimeWindow> {
        @Override
        public void apply(String key, TimeWindow window, Iterable<Tuple2<String, Integer>> input, org.apache.flink.util.Collector<Tuple3<String, Long, Long>> out) throws Exception {
            int count = 0;
            for (Tuple2<String, Integer> item : input) {
                count += item.f1;
            }
            out.collect(new Tuple3<>(key + "-" + count, window.getStart(), window.getEnd()));
        }
    }

    private static class TupleKeySelector implements org.apache.flink.api.java.functions.KeySelector<Tuple2<String, Integer>, String> {
        @Override
        public String getKey(Tuple2<String, Integer> value) throws Exception {
            return value.f0;
        }
    }

    private static <OUT> OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, OUT> createTestHarness(
            OneInputStreamOperatorFactory<Tuple2<String, Integer>, OUT> operator) {
        try {
            return new KeyedOneInputStreamOperatorTestHarness<>(
                    operator, new TupleKeySelector(), BasicTypeInfo.STRING_TYPE_INFO);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private static class Tuple2ResultSortComparator implements java.util.Comparator<Object> {
        @Override
        public int compare(Object o1, Object o2) {
            return 0; // Simplified for testing
        }
    }
}

