645:     /**
646:      * Deletes the cleanup timer set for the contents of the provided window.
647:      *
648:      * @param window the window whose state to discard
649:      */
650:     protected void deleteCleanupTimer(W window) {
651:         long cleanupTime = cleanupTime(window);
652:         if (cleanupTime == Long.MAX_VALUE) {
653:             // no need to clean up because we didn't set one
654:             return;
655:         }
656:         if (windowAssigner.isEventTime()) {
657:             triggerContext.deleteEventTimeTimer(cleanupTime);
658:         } else {
659:             triggerContext.deleteProcessingTimeTimer(cleanupTime);
660:         }
